import { describe, expect, it } from 'vitest';
import fs from 'node:fs';

const authorityFiles = [
  'docs/planning/XO_PHASE_2_IMPLEMENTATION_PLAN.md',
  'docs/planning/XO_PHASE_2_CHANT_IMPLEMENTATION_ROUTING.md',
  'docs/planning/XO_PHASE_2_CHANT_HANDOFF.md',
];

describe('XO Phase 2 planning authority', () => {
  it('preserves the supervised tutor non-negotiables', () => {
    const corpus = authorityFiles.map((file) => fs.readFileSync(file, 'utf8')).join('\n');
    expect(corpus).toMatch(/xo-phase2-bead-01/);
    expect(corpus).toMatch(/xo-phase2-bead-07/);
    expect(corpus).toMatch(/single-child|one-child/i);
    expect(corpus).toMatch(/lesson-bound/i);
    expect(corpus).toMatch(/guardian/i);
    expect(corpus).toMatch(/summary|disclosure/i);
  });
});

